import React, { useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { Card, Button, Container, Row, Col } from "react-bootstrap";
import { listCards } from "../../utils/api/index.js";

function Study({ decks }) {
  const [flipped, setFlipped] = useState(false);
  const [index, setIndex] = useState(0);
  const [cards, setCards] = useState([]);
  let content, nextButton;

  const params = useParams();
  const deck = decks.find((item) => item.id.toString() === params.deckId);

  useEffect(() => {
    async function loadCards() {
      const cardData = await listCards(deck.id);
      console.log(cardData)
      setCards(cards => cards = cardData);
    }
    loadCards();
  }, [])

  // Test to be sure cards and deck are present.
  if (!deck || cards.length === 0) {
    return <h4>Loading...</h4>;
  } else if (deck && cards.length <= 2) {
    return (
      <div>
        <h3>Not enough cards.</h3>
        <p>
          {" "}
          You need at least 3 cards to study. There{" "}
          {cards.length === 1 ? "is" : "are"} only {cards.length} card
          {cards.length === 1 ? null : "s"} in this deck.
        </p>
        <Link to="/">
          <Button>Add Cards</Button>
        </Link>
      </div>
    );
  }

  // Flip the card.
  if (flipped) {
    nextButton = (
      <Button
        onClick={() => {
          if (index < cards.length - 1) {
            setIndex((index) => index + 1);
            setFlipped(!flipped);
          } else {
            if (window.confirm("Would you like to restart the deck?")) {
              setIndex((index) => (index = 0)); // Maybe change this.
              setFlipped(!flipped);
            }
          }
        }}
        className="m-1"
      >
        Next
      </Button>
    );
    content = cards[index].back;
  } else {
    console.log("cards: ", cards)
    content = cards[index].front;
    nextButton = null;
  }

  return (
    <div>
      <h1>Study: {deck.name}</h1>
      <Card>
        <Card.Body>
          <Card.Title>
            Card {index + 1} of {cards.length}
          </Card.Title>
          <Card.Text>{content}</Card.Text>
          <Button
            onClick={() => setFlipped(!flipped)}
            variant="secondary"
            className="m-2"
          >
            Flip
          </Button>
          {nextButton}
        </Card.Body>
      </Card>
    </div>
  );
}

export default Study;
